import{c as a,Q as n,j as p,m as l}from"./chunks/framework.CBiVa4O3.js";const g=JSON.parse('{"title":"直播系统","description":"","frontmatter":{},"headers":[],"relativePath":"../systemDesign/20-直播系统.md","filePath":"../systemDesign/20-直播系统.md","lastUpdated":1778496697000}'),e={name:"../systemDesign/20-直播系统.md"};function t(i,s,o,r,h,c){return n(),p("div",null,[...s[0]||(s[0]=[l(`<h1 id="直播系统" tabindex="-1">直播系统 <a class="header-anchor" href="#直播系统" aria-label="Permalink to &quot;直播系统&quot;">​</a></h1><p>直播和视频点播看上去都是&quot;看视频&quot;,<strong>底层完全是两个世界</strong>——点播是「文件分发」,直播是「实时流」。点播的视频已经存在,你慢慢拉就行;直播的视频此刻正在产生,<strong>主播说的话 1 秒后必须到观众端</strong>——这 1 秒延迟里要做完编码 / 推流 / 转码 / CDN 分发 / 播放器解码,<strong>任何一步慢一点观众都骂卡</strong>。这一篇讲清楚直播的全链路,以及为什么&quot;超低延迟直播&quot;(电商带货 &lt; 500ms)和&quot;普通直播&quot;(秀场 3-5 秒)是两套完全不同的架构。</p><blockquote><p>一句话先记住:<strong>直播 = 推流(RTMP)+ 转码 + 分发(HLS / FLV / WebRTC)+ 播放</strong>。<strong>延迟决定方案</strong>——3-5 秒延迟用 HLS(便宜,CDN 友好);1 秒延迟用 HTTP-FLV(中等成本);&lt; 500ms 延迟用 WebRTC(贵,SFU 自建)。<strong>春晚级直播扛 2 亿同时在线靠的是层层 CDN 缓存</strong> —— 一个流复制到 1 万个 CDN 节点,而不是 2 亿个并发拉源站。</p></blockquote><hr><h2 id="一、需求拆解" tabindex="-1">一、需求拆解 <a class="header-anchor" href="#一、需求拆解" aria-label="Permalink to &quot;一、需求拆解&quot;">​</a></h2><h3 id="_1-1-功能需求" tabindex="-1">1.1 功能需求 <a class="header-anchor" href="#_1-1-功能需求" aria-label="Permalink to &quot;1.1 功能需求&quot;">​</a></h3><ul><li><strong>主播推流</strong>:摄像头 / 屏幕画面实时上传</li><li><strong>观众拉流</strong>:实时观看直播</li><li><strong>弹幕</strong>:观众发文字消息,所有人能看到</li><li><strong>点赞 / 礼物</strong>:实时互动</li><li><strong>录制回放</strong>:直播结束生成点播视频</li><li><strong>多档清晰度</strong>:观众选 360p / 720p / 1080p</li></ul><h3 id="_1-2-非功能需求" tabindex="-1">1.2 非功能需求 <a class="header-anchor" href="#_1-2-非功能需求" aria-label="Permalink to &quot;1.2 非功能需求&quot;">​</a></h3><ul><li><strong>延迟</strong>:普通直播 3-5 秒,电商 / 互动 &lt; 1 秒</li><li><strong>首帧时间</strong>:&lt; 1 秒</li><li><strong>稳定性</strong>:卡顿率 &lt; 1%</li><li><strong>规模</strong>:春晚级 2 亿同时在线;日常单场峰值 1000 万</li></ul><h3 id="_1-3-这一轮不做" tabindex="-1">1.3 这一轮不做 <a class="header-anchor" href="#_1-3-这一轮不做" aria-label="Permalink to &quot;1.3 这一轮不做&quot;">​</a></h3><ul><li>美颜 / 滤镜(端侧 SDK)</li><li>实时连麦(WebRTC P2P)</li><li>AI 主播 / 数字人</li></ul><hr><h2 id="二、容量估算" tabindex="-1">二、容量估算 <a class="header-anchor" href="#二、容量估算" aria-label="Permalink to &quot;二、容量估算&quot;">​</a></h2><h3 id="_2-1-流量估算" tabindex="-1">2.1 流量估算 <a class="header-anchor" href="#_2-1-流量估算" aria-label="Permalink to &quot;2.1 流量估算&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2 亿同时在线观众 × 720p 平均 2 Mbps</span></span>
<span class="line"><span>= 4 × 10^14 bps</span></span>
<span class="line"><span>= 400 Tbps</span></span>
<span class="line"><span>→ 单机房根本不可能,**必须 CDN 分发**</span></span>
<span class="line"><span></span></span>
<span class="line"><span>带宽成本:400 Tbps × 高峰 1 小时 = 144 PB / 小时</span></span>
<span class="line"><span>= 几千万人民币 / 小时</span></span></code></pre></div><h3 id="_2-2-推流端" tabindex="-1">2.2 推流端 <a class="header-anchor" href="#_2-2-推流端" aria-label="Permalink to &quot;2.2 推流端&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>日活主播 100 万,平均同时直播 5 万人</span></span>
<span class="line"><span>单主播上行 720p × 2 Mbps = 100 GB / 小时</span></span>
<span class="line"><span>日总推流量 = 5 万 × 24 × 100 GB ≈ 100 PB / 天</span></span></code></pre></div><h3 id="_2-3-弹幕" tabindex="-1">2.3 弹幕 <a class="header-anchor" href="#_2-3-弹幕" aria-label="Permalink to &quot;2.3 弹幕&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>2 亿观众,5% 活跃发弹幕</span></span>
<span class="line"><span>峰值弹幕 = 2 × 10^8 × 5% × 1 条/秒 = 1000 万 QPS</span></span>
<span class="line"><span></span></span>
<span class="line"><span>每条弹幕广播给 2 亿在线 → 投递 2 × 10^15 次/秒(完全不可能)</span></span>
<span class="line"><span>→ 弹幕必须采样 + 客户端聚合</span></span></code></pre></div><hr><h2 id="三、直播的关键参数-延迟" tabindex="-1">三、直播的关键参数:延迟 <a class="header-anchor" href="#三、直播的关键参数-延迟" aria-label="Permalink to &quot;三、直播的关键参数:延迟&quot;">​</a></h2><p>延迟决定一切:</p><table tabindex="0"><thead><tr><th>延迟</th><th>协议</th><th>适合</th><th>成本</th></tr></thead><tbody><tr><td>5-30 秒</td><td>HLS</td><td>普通直播(秀场、新闻)</td><td>极低,CDN 友好</td></tr><tr><td>1-3 秒</td><td>HTTP-FLV</td><td>中等互动(电竞直播)</td><td>低</td></tr><tr><td>500ms-1s</td><td>LL-HLS / CMAF</td><td>较高互动</td><td>中</td></tr><tr><td>&lt; 500ms</td><td>WebRTC</td><td>强互动(电商带货、连麦)</td><td>高,SFU 自建</td></tr></tbody></table><blockquote><p><strong>延迟越低成本越高</strong>——降一档延迟通常贵 5-10 倍。<strong>业务定要求,技术选方案</strong>。</p></blockquote><hr><h2 id="四、推流-从主播到服务器" tabindex="-1">四、推流:从主播到服务器 <a class="header-anchor" href="#四、推流-从主播到服务器" aria-label="Permalink to &quot;四、推流:从主播到服务器&quot;">​</a></h2><h3 id="_4-1-rtmp-推流" tabindex="-1">4.1 RTMP 推流 <a class="header-anchor" href="#_4-1-rtmp-推流" aria-label="Permalink to &quot;4.1 RTMP 推流&quot;">​</a></h3><p>主流方案:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>主播端(OBS / 直播 App)</span></span>
<span class="line"><span>   ↓ 编码 H.264</span></span>
<span class="line"><span>   ↓ 封装成 RTMP</span></span>
<span class="line"><span>   ↓ TCP 长连接推送</span></span>
<span class="line"><span>推流接入服务器(Nginx-RTMP / 自研)</span></span></code></pre></div><p><strong>RTMP</strong>:</p><ul><li>Adobe 1996 年发明,Flash 时代主流</li><li>基于 TCP,长连接</li><li>延迟 1-3 秒</li><li><strong>推流端事实标准</strong>(几乎所有摄像头、OBS 都默认 RTMP)</li></ul><h3 id="_4-2-推流接入" tabindex="-1">4.2 推流接入 <a class="header-anchor" href="#_4-2-推流接入" aria-label="Permalink to &quot;4.2 推流接入&quot;">​</a></h3><div class="language-python vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Nginx-RTMP 配置</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">rtmp {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    server {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        listen </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1935</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        application live {</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            live on;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            record off;</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 推流后触发转码</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">            on_publish http:</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">//</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">transcoder</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">publish;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">        }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    }</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p>主播推流 URL:<code>rtmp://push.example.com/live/{stream_key}</code>,<code>stream_key</code> 是临时凭证,过期失效。</p><h3 id="_4-3-推流的高可用" tabindex="-1">4.3 推流的高可用 <a class="header-anchor" href="#_4-3-推流的高可用" aria-label="Permalink to &quot;4.3 推流的高可用&quot;">​</a></h3><p><strong>接入层用 Anycast</strong> —— 主播推到「最近的接入点」,而不是固定某个机房。</p><p><strong>主备链路</strong>:</p><ul><li>推流端默认 4G,备用 WiFi</li><li>SDK 自动切换,断流自动重连</li><li>推流 URL 带「重连 token」,断后能恢复到原流</li></ul><hr><h2 id="五、转码-实时多档码率" tabindex="-1">五、转码:实时多档码率 <a class="header-anchor" href="#五、转码-实时多档码率" aria-label="Permalink to &quot;五、转码:实时多档码率&quot;">​</a></h2><p>和点播类似,但<strong>实时性要求高</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源流(主播推上来,1080p / 5 Mbps)</span></span>
<span class="line"><span>   ↓ 实时转码集群</span></span>
<span class="line"><span>[</span></span>
<span class="line"><span>  1080p / 5 Mbps  (原画)</span></span>
<span class="line"><span>  720p  / 2 Mbps</span></span>
<span class="line"><span>  480p  / 1 Mbps</span></span>
<span class="line"><span>  360p  / 500 Kbps</span></span>
<span class="line"><span>]</span></span></code></pre></div><p><strong>关键约束</strong>:</p><ul><li>每档延迟 &lt; 1 秒(否则首帧延迟太大)</li><li>必须 GPU(CPU 实时转码扛不住几十路并行)</li><li><strong>转码失败要 fallback</strong>(只输出原画,不阻塞分发)</li></ul><hr><h2 id="六、分发-从源站到观众" tabindex="-1">六、分发:从源站到观众 <a class="header-anchor" href="#六、分发-从源站到观众" aria-label="Permalink to &quot;六、分发:从源站到观众&quot;">​</a></h2><h3 id="_6-1-hls-分发-主流" tabindex="-1">6.1 HLS 分发(主流) <a class="header-anchor" href="#_6-1-hls-分发-主流" aria-label="Permalink to &quot;6.1 HLS 分发(主流)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>转码后输出 HLS:</span></span>
<span class="line"><span>  live.m3u8(滑动窗口 manifest)</span></span>
<span class="line"><span>  segment_001.ts</span></span>
<span class="line"><span>  segment_002.ts</span></span>
<span class="line"><span>  ...</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>HLS 标准:每段 2-10 秒</span></span>
<span class="line"><span>  → 延迟 = 段长 × 3(buffer 3 段)= 6-30 秒</span></span></code></pre></div><p><strong>优势</strong>:走 HTTP,<strong>完美 CDN 化</strong>。 <strong>劣势</strong>:延迟高。</p><h3 id="_6-2-http-flv-中延迟" tabindex="-1">6.2 HTTP-FLV(中延迟) <a class="header-anchor" href="#_6-2-http-flv-中延迟" aria-label="Permalink to &quot;6.2 HTTP-FLV(中延迟)&quot;">​</a></h3><p>类似 HLS 但<strong>用 HTTP 长连接持续推送 FLV 数据</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GET /live/stream_key.flv HTTP/1.1</span></span>
<span class="line"><span>Connection: keep-alive</span></span>
<span class="line"><span>→ 服务器持续返回 FLV 数据流</span></span></code></pre></div><p><strong>延迟 1-3 秒</strong>——比 HLS 短,因为不切段、立即转发。</p><p><strong>问题</strong>:<strong>长连接对 CDN 不友好</strong>——CDN 节点要保持连接,资源消耗大。<strong>只有专业直播 CDN 才支持</strong>。</p><h3 id="_6-3-ll-hls-low-latency-hls" tabindex="-1">6.3 LL-HLS(Low-Latency HLS) <a class="header-anchor" href="#_6-3-ll-hls-low-latency-hls" aria-label="Permalink to &quot;6.3 LL-HLS(Low-Latency HLS)&quot;">​</a></h3><p>苹果 2019 年提出,把 HLS 延迟从 30 秒降到 1-2 秒:</p><ul><li>段长缩短到 200ms</li><li>用 HTTP/2 推送</li><li>部分块(partial segment)技术</li></ul><p><strong>还在普及中</strong>,新设备支持好,老设备兼容性差。</p><h3 id="_6-4-webrtc-超低延迟" tabindex="-1">6.4 WebRTC(超低延迟) <a class="header-anchor" href="#_6-4-webrtc-超低延迟" aria-label="Permalink to &quot;6.4 WebRTC(超低延迟)&quot;">​</a></h3><p><strong>电商带货、互动直播专用</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>推流端 → SFU(Selective Forwarding Unit)</span></span>
<span class="line"><span>        ↓</span></span>
<span class="line"><span>      转发给所有观众端</span></span>
<span class="line"><span>延迟 &lt; 500ms</span></span></code></pre></div><p><strong>优势</strong>:延迟极低。 <strong>劣势</strong>:</p><ul><li>WebRTC 是 P2P 设计,改成 SFU 模式工程量大</li><li>不能用 HTTP CDN(协议不兼容)</li><li>必须自建 SFU 集群,成本高</li></ul><blockquote><p><strong>2026 年的现状</strong>:头部电商(淘宝、抖音电商)已经全面 WebRTC,<strong>CDN 厂商提供 SFU 服务</strong>(阿里云直播 RTC、腾讯云 TRTC)。</p></blockquote><hr><h2 id="七、cdn-分发-春晚级流量怎么扛" tabindex="-1">七、CDN 分发:春晚级流量怎么扛 <a class="header-anchor" href="#七、cdn-分发-春晚级流量怎么扛" aria-label="Permalink to &quot;七、CDN 分发:春晚级流量怎么扛&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>直播流到源站</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>推到上层 CDN(20 个核心节点)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>推到中层 CDN(200 个区域节点)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>推到边缘 CDN(几千个边缘节点,靠近用户)</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>2 亿观众就近拉边缘节点</span></span></code></pre></div><p><strong>关键:CDN 是树形分发,不是全部回源</strong>。</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>不分发:2 亿用户 × 2 Mbps = 400 Tbps 都打源站(完全不可能)</span></span>
<span class="line"><span>CDN 分发:</span></span>
<span class="line"><span>  源站 → 20 个核心节点(20 个流复制)</span></span>
<span class="line"><span>  核心 → 200 个区域(放大 10 倍)</span></span>
<span class="line"><span>  区域 → 几千个边缘(放大 25 倍)</span></span>
<span class="line"><span>  边缘 → 几千万用户(放大 1 万倍)</span></span>
<span class="line"><span>  </span></span>
<span class="line"><span>源站只发了 20 路,2 亿用户都看到了</span></span></code></pre></div><p><strong>这就是 CDN 的&quot;放大效应&quot;</strong>——<strong>直播是 CDN 最适合的场景</strong>(同一份数据被无限多人需要)。</p><hr><h2 id="八、弹幕系统" tabindex="-1">八、弹幕系统 <a class="header-anchor" href="#八、弹幕系统" aria-label="Permalink to &quot;八、弹幕系统&quot;">​</a></h2><p>弹幕的工程难度<strong>不亚于直播本身</strong>——10 万 / 100 万人在线时,1 秒钟有几万条弹幕,扩散给所有人。</p><h3 id="_8-1-朴素方案-行不通" tabindex="-1">8.1 朴素方案(行不通) <a class="header-anchor" href="#_8-1-朴素方案-行不通" aria-label="Permalink to &quot;8.1 朴素方案(行不通)&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>观众发弹幕 → 推给所有在线观众</span></span>
<span class="line"><span>1 万人发,2 亿人收 → 1 万 × 2 亿 = 2 万亿次推送/秒</span></span>
<span class="line"><span>→ 直接挂</span></span></code></pre></div><h3 id="_8-2-实战方案-采样-聚合-分级" tabindex="-1">8.2 实战方案:采样 + 聚合 + 分级 <a class="header-anchor" href="#_8-2-实战方案-采样-聚合-分级" aria-label="Permalink to &quot;8.2 实战方案:采样 + 聚合 + 分级&quot;">​</a></h3><h4 id="采样" tabindex="-1">采样 <a class="header-anchor" href="#采样" aria-label="Permalink to &quot;采样&quot;">​</a></h4><p>不是每条弹幕都广播——<strong>热门弹幕广播,冷门弹幕只发给附近的人</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>单房间 100 万弹幕/分钟</span></span>
<span class="line"><span>采样到 1 万条/分钟广播给所有人</span></span>
<span class="line"><span>其余只在小范围(同一设备类型 / 同一地区)显示</span></span></code></pre></div><p>用户不会知道——反正屏幕也放不下那么多。</p><h4 id="聚合" tabindex="-1">聚合 <a class="header-anchor" href="#聚合" aria-label="Permalink to &quot;聚合&quot;">​</a></h4><p>类似弹幕合并:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;哈哈哈哈哈&quot; &quot;哈哈哈&quot; &quot;哈哈&quot; → 合并显示一次</span></span>
<span class="line"><span>&quot;666&quot; 大量出现 → 只显示一条 + 计数</span></span></code></pre></div><h4 id="分级" tabindex="-1">分级 <a class="header-anchor" href="#分级" aria-label="Permalink to &quot;分级&quot;">​</a></h4><p>VIP 弹幕、彩色弹幕、礼物弹幕优先广播,普通弹幕降级。</p><h3 id="_8-3-弹幕的存储" tabindex="-1">8.3 弹幕的存储 <a class="header-anchor" href="#_8-3-弹幕的存储" aria-label="Permalink to &quot;8.3 弹幕的存储&quot;">​</a></h3><p><strong>写入</strong>:Kafka(削峰) <strong>实时分发</strong>:Redis Pub/Sub 或自研推送 <strong>回放</strong>:存到对象存储,直播结束后做录播弹幕</p><hr><h2 id="九、礼物-互动" tabindex="-1">九、礼物 / 互动 <a class="header-anchor" href="#九、礼物-互动" aria-label="Permalink to &quot;九、礼物 / 互动&quot;">​</a></h2><p>电商带货 / 秀场的核心收入来源:</p><h3 id="_9-1-礼物的特殊要求" tabindex="-1">9.1 礼物的特殊要求 <a class="header-anchor" href="#_9-1-礼物的特殊要求" aria-label="Permalink to &quot;9.1 礼物的特殊要求&quot;">​</a></h3><ul><li><strong>强一致</strong>:用户花钱买的礼物,<strong>必须送到主播账户</strong></li><li><strong>实时显示</strong>:观众和主播都要立即看到</li><li><strong>防作弊</strong>:防止重放攻击、客户端伪造</li></ul><h3 id="_9-2-流程" tabindex="-1">9.2 流程 <a class="header-anchor" href="#_9-2-流程" aria-label="Permalink to &quot;9.2 流程&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>观众点礼物</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>扣钱(同步,DB 事务)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>异步推送礼物消息(类似弹幕,但优先级更高)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>主播看到 + 所有观众看到</span></span></code></pre></div><p><strong>扣钱必须同步,推送可以异步</strong>。</p><hr><h2 id="十、录制-回放" tabindex="-1">十、录制 / 回放 <a class="header-anchor" href="#十、录制-回放" aria-label="Permalink to &quot;十、录制 / 回放&quot;">​</a></h2><p>直播结束 → 自动生成点播视频:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>推流接入时同步保存原始流到对象存储</span></span>
<span class="line"><span>直播结束 → 转码 + 切片 → 生成回放视频</span></span>
<span class="line"><span>回放接入点播系统(详见 19 篇)</span></span></code></pre></div><p><strong>关键</strong>:<strong>录制不能影响直播主路径</strong>——独立 Worker,失败也不影响直播。</p><hr><h2 id="十一、跨地域分发-全球直播" tabindex="-1">十一、跨地域分发:全球直播 <a class="header-anchor" href="#十一、跨地域分发-全球直播" aria-label="Permalink to &quot;十一、跨地域分发:全球直播&quot;">​</a></h2><p>世界杯、海外直播:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>源站(主播所在地区)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>跨洋推送到各大区源站(中转 CDN)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>各区域 CDN 分发本地观众</span></span></code></pre></div><p><strong>跨洋推送只一次</strong>——不是每个观众都跨洋拉。</p><p><strong>延迟代价</strong>:跨洋光纤本身 200ms,<strong>跨地域直播必然延迟更高</strong>。</p><hr><h2 id="十二、关键工程挑战" tabindex="-1">十二、关键工程挑战 <a class="header-anchor" href="#十二、关键工程挑战" aria-label="Permalink to &quot;十二、关键工程挑战&quot;">​</a></h2><h3 id="_12-1-主播突然断流" tabindex="-1">12.1 主播突然断流 <a class="header-anchor" href="#_12-1-主播突然断流" aria-label="Permalink to &quot;12.1 主播突然断流&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>4G 信号差 → 推流断</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>观众端继续看 5 秒缓存</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>还没恢复 → 显示&quot;主播暂时离开&quot;</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>主播恢复 → 重新推流(同 stream_key)</span></span>
<span class="line"><span>   ↓</span></span>
<span class="line"><span>观众无感切回</span></span></code></pre></div><h3 id="_12-2-观众千万人同时进直播间" tabindex="-1">12.2 观众千万人同时进直播间 <a class="header-anchor" href="#_12-2-观众千万人同时进直播间" aria-label="Permalink to &quot;12.2 观众千万人同时进直播间&quot;">​</a></h3><p>春晚 / 大型活动:</p><ul><li><strong>预热 CDN</strong>:开播前推流到所有边缘节点</li><li><strong>限流</strong>:超过容量返回排队 / 兜底</li><li><strong>降级</strong>:网络拥堵时强制低码率</li></ul><h3 id="_12-3-鉴权和反盗播" tabindex="-1">12.3 鉴权和反盗播 <a class="header-anchor" href="#_12-3-鉴权和反盗播" aria-label="Permalink to &quot;12.3 鉴权和反盗播&quot;">​</a></h3><ul><li><strong>拉流 URL 签名</strong>(同点播)</li><li><strong>设备指纹检测</strong>(同 IP 同时拉 100 路 → 怀疑是盗播服务器)</li><li><strong>DRM</strong>(付费内容)</li></ul><hr><h2 id="十三、最终架构图" tabindex="-1">十三、最终架构图 <a class="header-anchor" href="#十三、最终架构图" aria-label="Permalink to &quot;十三、最终架构图&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>                       主播端</span></span>
<span class="line"><span>                         ↓ RTMP</span></span>
<span class="line"><span>                   就近接入 (Anycast)</span></span>
<span class="line"><span>                         ↓</span></span>
<span class="line"><span>                   源站 RTMP 接入</span></span>
<span class="line"><span>                         ↓</span></span>
<span class="line"><span>              ┌──────────┼──────────┐</span></span>
<span class="line"><span>              ↓          ↓          ↓</span></span>
<span class="line"><span>         实时转码      录制       推到 CDN 上层</span></span>
<span class="line"><span>         (GPU)       (异步)</span></span>
<span class="line"><span>              ↓                      ↓</span></span>
<span class="line"><span>         多档码率             ┌─────────────┐</span></span>
<span class="line"><span>              ↓               │ CDN 树形分发 │</span></span>
<span class="line"><span>         上层 CDN(20)──────→│  上层→中层    │</span></span>
<span class="line"><span>              ↓               │  中层→边缘    │</span></span>
<span class="line"><span>         中层 CDN(200)       │  边缘→用户    │</span></span>
<span class="line"><span>              ↓               └──────┬──────┘</span></span>
<span class="line"><span>         边缘 CDN(几千)            ↓</span></span>
<span class="line"><span>                                  观众端</span></span>
<span class="line"><span>                                  (HLS/FLV/WebRTC)</span></span>
<span class="line"><span></span></span>
<span class="line"><span>弹幕通道:</span></span>
<span class="line"><span>  观众 → 弹幕服务 → Kafka → 分发服务 → 推回所有观众</span></span></code></pre></div><hr><h2 id="十四、踩坑提醒" tabindex="-1">十四、踩坑提醒 <a class="header-anchor" href="#十四、踩坑提醒" aria-label="Permalink to &quot;十四、踩坑提醒&quot;">​</a></h2><ol><li><strong>直播用 HTTP 短连接拉</strong>——延迟和卡顿都崩</li><li><strong>不分级延迟方案</strong>——用 WebRTC 做秀场,成本爆炸</li><li><strong>HLS 段长设太长</strong>(10 秒)——延迟 30 秒+</li><li><strong>不用 CDN 树形分发</strong>——源站直接被 2 亿用户打挂</li><li><strong>弹幕全量广播</strong>——10 万 × 2 亿次推送,集群崩</li><li><strong>转码用 CPU</strong>——GPU 才能扛实时多档转码</li><li><strong>不监控推流断</strong>——主播断了几分钟才发现</li><li><strong>首帧不优化</strong>——观众点开等 5 秒,流失严重</li><li><strong>CDN 不预热大型活动</strong>——春晚开播瞬间所有节点回源</li><li><strong>录制和直播共用资源</strong>——录制慢拖累直播</li><li><strong>没准备超低码率档</strong>(180p)——网络极差用户完全看不了</li><li><strong>不限流容量</strong>——超过设计容量直播全挂</li></ol><hr><p>下一篇:<code>21-网约车.md</code>,讲滴滴 / Uber 的核心难题——<strong>地理位置匹配 + 实时定位</strong>。GeoHash 怎么做空间索引、司机端每秒上报位置怎么不打挂 DB、派单算法怎么在 1 秒内从几千司机里挑最优、订单状态机怎么设计才不会漏单或重复扣钱。</p>`,123)])])}const u=a(e,[["render",t]]);export{g as __pageData,u as default};
